import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { GradebookRow } from '../../core/models';

/**
 * LearnLoop gradebook — a table of enrolled students × quizzes plus each
 * student's overall course progress %. Loads via ApiService.getGradebook(id).
 */
@Component({
  selector: 'app-gradebook',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './gradebook.component.html',
  styleUrl: './gradebook.component.css',
})
export class GradebookComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly rows = signal<GradebookRow[]>([
    {
      userId: 'u1',
      studentName: 'Ada Lovelace',
      studentEmail: 'ada@demo',
      progressPct: 100,
      scores: [
        { quizId: 'q1', quizTitle: 'CSS Fundamentals Quiz', scorePct: 90 },
        { quizId: 'q2', quizTitle: 'JS Basics Quiz', scorePct: 80 },
      ],
    },
    {
      userId: 'u2',
      studentName: 'Grace Hopper',
      studentEmail: 'grace@demo',
      progressPct: 60,
      scores: [
        { quizId: 'q1', quizTitle: 'CSS Fundamentals Quiz', scorePct: 70 },
        { quizId: 'q2', quizTitle: 'JS Basics Quiz', scorePct: null },
      ],
    },
    {
      userId: 'u3',
      studentName: 'Alan Turing',
      studentEmail: 'alan@demo',
      progressPct: 25,
      scores: [
        { quizId: 'q1', quizTitle: 'CSS Fundamentals Quiz', scorePct: 50 },
        { quizId: 'q2', quizTitle: 'JS Basics Quiz', scorePct: null },
      ],
    },
  ]);

  courseId = '';

  // Column headers derived from the first row's quiz list.
  readonly quizColumns = computed(() => {
    const first = this.rows()[0];
    return first ? first.scores.map((s) => ({ quizId: s.quizId, quizTitle: s.quizTitle })) : [];
  });

  constructor(private api: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.courseId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getGradebook(this.courseId).subscribe({
      next: (rows) => {
        this.rows.set(rows);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load the gradebook. Please try again.');
        this.loading.set(false);
      },
    });
  }

  scoreClass(score: number | null): string {
    if (score == null) return 'muted';
    return score >= 70 ? 'pass' : 'fail';
  }
}
